33. ## Step 2 ΓÇö `{StepName}Client.tsx` (Client Component)
34. 
35. ```tsx
36. 'use client';
37. 
38. import { useEffect, useMemo, useState } from 'react';
39. import { analyticsService, matomo } from '@/libs/matomo';
40. import {
41.   useGetSomeDataQuery,
42.   useSaveDataMutation,
43.   useGetOnboardingStatusQuery,
44. } from '@/libs/store/api/onboardingApi';
45. import { useOnboardingWorkflowPage } from '@/hooks/useOnboardingWorkflowPage';
46. import PresentationComponent from '@/subframe-pages/Onboarding/{PresentationComponent}';
47. import { PortalLoader } from '@/components/PortalLoader';
48. import type { SomeType } from '@/types/onboarding';
49. 
50. function {StepName}Client() {
51.   // 1. Onboarding workflow hook ΓÇö manages sidebar stepper + step validation
52.   //    expectedStepIndex: 0=Confirm Portfolio, 1=Set Goals, 2=Key Insights, 3=Review Data
53.   const { isReady, router } = useOnboardingWorkflowPage({
54.     expectedStepIndex: N,              // 0-based step index
55.     sidebarDescription: 'Description shown in the sidebar for this step.',
56.   });
57. 
58.   // 2. Analytics module (FIRST useEffect)
59.   useEffect(() => {
60.     analyticsService.setModule('onboarding-{step-name}');
61.   }, []);
62. 
63.   // 3. RTK Query hooks ΓÇö queries + mutations
64.   const { data, isLoading, error } = useGetSomeDataQuery();
65.   const [saveData, { isLoading: isSaving }] = useSaveDataMutation();
66.   const { refetch: refetchOnboardingStatus } = useGetOnboardingStatusQuery();
67. 
68.   // 4. Local state for user edits (if needed)
69.   const [localData, setLocalData] = useState<SomeType[] | null>(null);
70. 
71.   // 5. Sync API data to local state on first load
72.   useEffect(() => {
73.     if (data?.data && localData === null) {
74.       setLocalData([...data.data]);
75.     }
76.   }, [data, localData]);
77. 
78.   // 6. Derived state with useMemo
79.   const displayData = useMemo(() => {
80.     return localData ?? data?.data ?? [];
81.   }, [localData, data]);
82. 
83.   // 7. Loading gate ΓÇö AFTER all hooks
84.   if (isLoading || !isReady) {
85.     return <PortalLoader />;
86.   }
87. 
88.   // 8. Event handlers ΓÇö track all user actions
89.   const handleAction = () => {
90.     analyticsService.trackClick({
91.       source: '{step-name}-page',
92.       target: '{action}-button',
93.       action: matomo.ACTION_TYPES.{TYPE},
94.     });
95.     // ... handler logic
96.   };
97. 
98.   const handleSubmitAndContinue = async (submittedData: SomeType[]) => {
99.     analyticsService.trackClick({
100.       source: '{step-name}-page',
101.       target: 'continue-button',
102.       action: matomo.ACTION_TYPES.SUBMIT,
103.     });
104.     try {
105.       await saveData({ data: submittedData }).unwrap();
106.       await refetchOnboardingStatus();
107.       analyticsService.trackEvent({
108.         eventType: 'save-success',
109.         eventParams: {
110.           source: '{step-name}-page',
111.           target: 'save',
112.           action: matomo.ACTION_TYPES.SUCCESS,
113.         },
114.       });
115.       router.push('/onboarding/{next-step}');
116.     } catch (err) {
117.       console.error('Failed to save:', err);
118.       analyticsService.trackEvent({
119.         eventType: 'save-failure',
120.         eventParams: {
121.           source: '{step-name}-page',
122.           target: 'save',
123.           action: matomo.ACTION_TYPES.FAILURE,
124.         },
125.       });
126.     }
127.   };
128. 
129.   const handleGoBack = () => {
130.     analyticsService.trackClick({
131.       source: '{step-name}-page',
132.       target: 'back-button',
133.       action: matomo.ACTION_TYPES.VIEW,
134.     });
135.     router.push('/onboarding/{previous-step}');
136.   };
137. 
138.   // 9. Render presentation component
139.   return (
140.     <PresentationComponent
141.       data={displayData}
142.       onSubmit={handleSubmitAndContinue}
143.       onGoBack={handleGoBack}
144.       isLoading={isSaving}
145.     />
146.   );
147. }
148. 
149. export default {StepName}Client;
150. ```
151. 
152. ## Key Differences from Admin Pages
153. 
154. | Concern | Admin | Onboarding |
155. |---------|-------|------------|
156. | **Workflow hook** | `useAdminWorkflowPage` | `useOnboardingWorkflowPage` |
157. | **Status hook** | `useOrganizationStatus` (needs orgId from URL) | `useOnboardingStatus` (no URL params) |
158. | **Route groups** | `(with-sidebar)/(with-breadcrumbs-and-stepper)/` | `(with-max-topbar)/(with-sidebar)/(with-default-scroll)/(with-content-and-stepper)/` |
159. | **URL params** | Always `?id=${orgId}` | No URL params ΓÇö status is user-scoped |
160. | **Sidebar** | Breadcrumbs + stepper via `useBreadcrumbContext` | Content description + stepper via `useContentAndStepperContext` |
161. | **API file** | `adminOrganizationApi.ts` | `onboardingApi.ts` |
162. | **Animations** | `AnimatePresence` + `motion.div` | Optional ΓÇö depends on design |
163. | **Refetch status** | Automatic via `invalidatesTags` | Must explicitly call `refetchOnboardingStatus()` after mutations |
164. 
165. ## Step Validation Flow
166. 
167. `useOnboardingStatus` handles:
168. - **Progressive workflow** ΓÇö can't skip ahead to incomplete steps
169. - **Backwards navigation** ΓÇö completed steps are clickable
170. - **Auto-redirect** ΓÇö accessing an invalid step redirects to the current step
171. - **`isReady`** ΓÇö only `true` when status is loaded AND step is valid
172. 
173. ## Corresponding Changes Required
174. 
175. - [ ] Add API endpoint to `src/libs/http/api-endpoints.ts`
176. - [ ] Add types to `src/types/onboarding.ts`
177. - [ ] Add RTK Query endpoint + MSW mock to `src/libs/store/api/onboardingApi.ts` (use **creating-rtk-query-endpoints** skill)
178. - [ ] Update `src/utils/computeOnboardingSteps.ts` if step order or count changes
179. - [ ] Update `ONBOARDING_STEP_ROUTES` array in `computeOnboardingSteps.ts`
180. - [ ] Add `data-testid` to all interactive elements (use **adding-data-test-ids** skill)
181. - [ ] Add presentation component to `src/subframe-pages/Onboarding/`
182. 
183. ## Critical Rules
184. 
185. 1. **All hooks BEFORE conditional returns** ΓÇö no exceptions
186. 2. **`PortalLoader`** for loading ΓÇö never `null`, never custom spinners
187. 3. **Never modify `src/ui/`** ΓÇö Subframe-generated, read-only
188. 4. **Refetch onboarding status** after mutations that advance the workflow
189. 5. **Track all user actions** ΓÇö clicks, saves, navigate back, success, failure
190. 6. **Never auto-commit** ΓÇö leave as modified files
191.

