172.         return HttpResponse.json({
173.           success: true,
174.           data: { id: Date.now(), ...body },
175.           message: 'Resource created successfully',
176.         });
177.       });
178.     },
179.   },
180. 
181.   // --- POST mutation with FormData (file upload) ---
182.   {
183.     url: `${BASE_URL.DATAHUB}${API_ENDPOINTS.FEATURE_UPLOAD}`,
184.     endpoint: 'uploadFile',
185.     builder(builder: QueryBuilder, url: string) {
186.       return builder.mutation<UploadResponse, { id: number; file: File }>({
187.         query: ({ id, file }) => {
188.           const formData = new FormData();
189.           formData.append('file', file);
190.           return {
