211.   // --- DELETE mutation ---
212.   {
213.     url: `${BASE_URL.DATAHUB}${API_ENDPOINTS.FEATURE_DELETE}`,
214.     endpoint: 'deleteResource',
215.     builder(builder: QueryBuilder, url: string) {
216.       return builder.mutation<DeleteResponse, { id: number }>({
217.         query: ({ id }) => ({
