1. /**
2.  * useOnboardingWorkflowPage Hook
3.  *
4.  * Consolidates common onboarding workflow page logic:
5.  * - Onboarding status management
6.  * - Sidebar content + stepper setup via WithContentAndStepperLayout context
7.  * - Conditional redirects
8.  *
9.  * @example
10.  * ```tsx
11.  * const { isReady, onboardingData } = useOnboardingWorkflowPage({
12.  *   expectedStepIndex: 0,
13.  *   sidebarDescription: "First, let's confirm your portfolio.",
14.  * });
15.  *
16.  * if (!isReady) return <PortalLoader />;
17.  * ```
18.  */
19. 
20. import { useEffect } from 'react';
21. import { useRouter } from 'next/navigation';
22. import { useOnboardingStatus } from '@/hooks/useOnboardingStatus';
23. import { useContentAndStepperContext } from '@/layouts/WithContentAndStepperLayout';
24. import type { OnboardingStepComputed, OnboardingStatus } from '@/types/onboarding';
25. import type { ContentAndStepperStepData } from '@/layouts/WithContentAndStepperLayout';
26. 
27. interface UseOnboardingWorkflowPageOptions {
28.   /**
29.    * The expected step index for this page (0-based).
30.    */
31.   expectedStepIndex: number;
32. 
33.   /**
34.    * Description text shown in the sidebar below the "MAX" title.
35.    */
36.   sidebarDescription: string;
37. 
38.   /**
39.    * Optional function to check if a redirect should occur.
40.    * @returns Redirect URL if should redirect, null otherwise
41.    */
42.   redirectCheck?: (onboardingData: OnboardingStatus | null) => string | null;
43. }
44. 
45. interface UseOnboardingWorkflowPageReturn {
46.   /** Whether the page is ready to render */
47.   isReady: boolean;
48.   /** True if the current step is already completed */
49.   isStepCompleted: boolean;
50.   /** Next.js router instance */
51.   router: ReturnType<typeof useRouter>;
52.   /** Current onboarding data from API */
53.   onboardingData: OnboardingStatus | null;
54.   /** Computed workflow steps */
55.   steps: OnboardingStepComputed[];
56.   /** Formatted steps for ProfileSetupCard */
57.   profileSetupSteps: ContentAndStepperStepData[];
58.   /** Progress text (e.g., "1 of 4 complete") */
59.   progressText: string;
60.   /** Progress percentage value */
61.   progressValue: number;
62. }
63. 
64. export function useOnboardingWorkflowPage(
65.   options: UseOnboardingWorkflowPageOptions
66. ): UseOnboardingWorkflowPageReturn {
67.   const { expectedStepIndex, sidebarDescription, redirectCheck } = options;
68. 
69.   const router = useRouter();
70. 
71.   const {
72.     isReady,
73.     isStepCompleted,
74.     onboardingData,
75.     steps,
76.     profileSetupSteps,
77.     progressText,
78.     progressValue,
79.   } = useOnboardingStatus({ expectedStepIndex });
80. 
81.   const { setSidebarData } = useContentAndStepperContext();
82. 
83.   // Set sidebar content and stepper in layout context
84.   useEffect(() => {
85.     if (!isReady) return;
86. 
87.     setSidebarData({
88.       content: {
89.         title: 'MAX',
90.         description: sidebarDescription,
91.       },
92.       stepperTitle: 'Complete your profile setup',
93.       stepperSteps: profileSetupSteps,
94.       stepperProgressText: progressText,
95.     });
96.   // eslint-disable-next-line react-hooks/exhaustive-deps
97.   }, [isReady, progressValue, profileSetupSteps]);
98. 
99.   // Handle conditional redirect if redirectCheck is provided
100.   useEffect(() => {
101.     if (!isReady || !redirectCheck || isStepCompleted) return;
102. 
103.     const redirectUrl = redirectCheck(onboardingData);
104.     if (redirectUrl) {
105.       router.push(redirectUrl);
106.     }
107.   }, [isReady, onboardingData, redirectCheck, router, isStepCompleted]);
108. 
109.   return {
110.     isReady,
111.     isStepCompleted,
112.     router,
113.     onboardingData,
114.     steps,
115.     profileSetupSteps,
116.     progressText,
117.     progressValue,
118.   };
119. }
