Used tool: view

Result: {
  "resultType": "success",
  "textResultForLlm": "1. 'use client';
2. 
3. import { useEffect, useMemo, useState } from 'react';
4. import { analyticsService, matomo } from '@/libs/matomo';
5. import {
6.   useGetPortfolioDataQuery,
7.   useSavePortfolioMutation,
8.   useGetOnboardingStatusQuery,
9. } from '@/libs/store/api/onboardingApi';
10. import { useOnboardingWorkflowPage } from '@/hooks/useOnboardingWorkflowPage';
11. import ConfirmPortfolio from '@/subframe-pages/Onboarding/ConfirmPortfolio';
12. import { PortalLoader } from '@/components/PortalLoader';
13. import type { PortfolioCategory, CategoryListItem, LocationListItem } from '@/types/onboarding';
14. 
15. /** Temporary id prefix for newly-added (pending) categories */
16. const PENDING_PREFIX = 'pending-';
17. 
18. function ConfirmPortfolioClient() {
19.   // ----- Workflow page hook (sidebar + stepper + step validation) -----
20.   const { isReady, router } = useOnboardingWorkflowPage({
21.     expectedStepIndex: 0,
22.     sidebarDescription:
23.       "First, let's confirm what categories & geographies your portfolio includes.",
24.   });
25. 
26.   // ----- Analytics -----
27.   useEffect(() => {
28.     analyticsService.setModule('onboarding-confirm-portfolio');
29.   }, []);
30. 
31.   // ----- RTK Query hooks (all before conditional returns) -----
32.   const { data, isLoading, error } = useGetPortfolioDataQuery();
33.   const [savePortfolio, { isLoading: isSaving }] = useSavePortfolioMutation();
34.   const { refetch: refetchOnboardingStatus } = useGetOnboardingStatusQuery();
35. 
36.   // ----- Local state: categories managed before submit -----
37.   const [localCategories, setLocalCategories] = useState<PortfolioCategory[] | null>(null);
38.   const [addingLocationForCategoryId, setAddingLocationForCategoryId] = useState<string | null>(null);
39. 
40.   // Initialise local state from API data once
41.   useEffect(() => {
42.     if (data?.data?.categories && localCategories === null) {
43.       setLocalCategories([...data.data.categories]);
44.     }
45.   }, [data, localCategories]);
46. 
47.   // Effective categories (local override or API data)
48.   const categories = useMemo(() => {
49.     return localCategories ?? data?.data?.categories ?? [];
50.   }, [localCategories, data]);
51. 
52.   const portfolioData = useMemo(() => {
53.     return {
54.       categories,
55.       totalCount: categories.length,
56.     };
57.   }, [categories]);
58. 
59.   // IDs of categories that are "pending" (user added but hasn't selected from combobox yet)
60.   const pendingCategoryIds = useMemo(() => {
61.     return categories
62.       .filter((cat: PortfolioCategory) => cat.id.startsWith(PENDING_PREFIX))
63.       .map((cat: PortfolioCategory) => cat.id);
64.   }, [categories]);
65. 
66.   // ----- Conditional returns AFTER all hooks -----
67.   if (isLoading || !isReady) {
68.     return <PortalLoader />;
69.   }
70. 
71.   // ----- Event handlers -----
72. 
73.   /** "Add a Category" ΓÇö creates a placeholder card with a combobox */
74.   const handleAddCategory = () => {
75.     analyticsService.trackClick({
76.       source: 'confirm-portfolio-form',
77.       target: 'add-category-button',
78.       action: matomo.ACTION_TYPES.OPEN,
79.     });
80. 
81.     const tempId = `${PENDING_PREFIX}${Date.now()}`;
82.     const newCategory: PortfolioCategory = { id: tempId, title: '', geographies: [] };
83.     setLocalCategories((prev) => [...(prev ?? []), newCategory]);
84.   };
85. 
86.   /** Combobox selected a real category ΓÇö replace the pending stub */
87.   const handleSelectCategory = (tempId: string, selected: CategoryListItem) => {
88.     analyticsService.trackClick({
89.       source: 'confirm-portfolio-form',
90.       target: 'select-category',
91.       action: matomo.ACTION_TYPES.ACCESS,
92.     });
93. 
94.     setLocalCategories((prev) =>
95.       (prev ?? []).map((cat) =>
96.         cat.id === tempId
97.           ? { id: selected.id, title: selected.title, geographies: [] }
98.           : cat,
99.       ),
100.     );
101.   };
102. 
103.   /** Remove a category card (works for both real & pending) */
104.   const handleRemoveCategory = (categoryId: string) => {
105.     analyticsService.trackClick({
106.       source: 'confirm-portfolio-form',
107.       target: 'remove-category-button',
108.       action: matomo.ACTION_TYPES.CLOSE,
109.     });
110. 
111.     setLocalCategories((prev) => (prev ?? []).filter((cat) => cat.id !== categoryId));
112.   };
113. 
114.   /** "Apply & Continue" ΓÇö saves and navigates */
115.   const handleApplyAndContinue = async (submittedCategories: PortfolioCategory[]) => {
116.     analyticsService.trackClick({
117.       source: 'confirm-portfolio-form',
118.       target: 'apply-continue-button',
119.       action: matomo.ACTION_TYPES.ACCESS,
120.     });
121. 
122.     // Filter out any still-pending (unselected) placeholder categories
123.     const validCategories = submittedCategories.filter(
124.       (cat) => !cat.id.startsWith(PENDING_PREFIX),
125.     );
126. 
127.     try {
128.       await savePortfolio({ categories: validCategories }).unwrap();
129. 
130.       analyticsService.trackEvent({
131.         eventType: 'portfolio-save-success',
132.         eventParams: {
133.           source: 'confirm-portfolio-form',
134.           target: 'portfolio-save',
135.           action: matomo.ACTION_TYPES.SUCCESS,
136.         },
137.       });
138. 
139.       // Refetch onboarding status to mark step as done
140.       await refetchOnboardingStatus();
141. 
142.       router.push('/onboarding/set-goals');
143.     } catch (err) {
144.       analyticsService.trackEvent({
145.         eventType: 'portfolio-save-failure',
146.         eventParams: {
147.           source: 'confirm-portfolio-form',
148.           target: 'portfolio-save',
149.           action: matomo.ACTION_TYPES.FAILURE,
150.         },
151.       });
152.       console.error('Failed to save portfolio:', err);
153.     }
154.   };
155. 
156.   /** Delete a geography tag from a category (local state only) */
157.   const handleDeleteGeography = (
158.     categoryId: string,
159.     geographyName: string,
160.   ): void => {
161.     analyticsService.trackClick({
162.       source: 'confirm-portfolio-form',
163.       target: 'delete-geography-button',
164.       action: matomo.ACTION_TYPES.CLOSE,
165.     });
166. 
167.     // Update local state only - API call happens on "Apply & Continue"
168.     setLocalCategories((prev) =>
169.       (prev ?? []).map((cat) =>
170.         cat.id === categoryId
171.           ? { ...cat, geographies: cat.geographies.filter(geo => geo !== geographyName) }
172.           : cat,
173.       ),
174.     );
175. 
176.     analyticsService.trackEvent({
177.       eventType: 'geography-delete-local',
178.       eventParams: {
179.         source: 'confirm-portfolio-form',
180.         target: 'geography-delete',
181.         action: matomo.ACTION_TYPES.SUCCESS,
182.       },
183.     });
184.   };
185. 
186.   /** Go back to onboarding landing */
187.   const handleGoBack = () => {
188.     analyticsService.trackClick({
189.       source: 'confirm-portfolio-form',
190.       target: 'go-back-button',
191.       action: matomo.ACTION_TYPES.VIEW,
192.     });
193.     router.push('/onboarding');
194.   };
195. 
196.   /** "Add Location" ΓÇö opens the LocationCombobox for a specific category */
197.   const handleAddLocation = (categoryId: string) => {
198.     analyticsService.trackClick({
199.       source: 'confirm-portfolio-form',
200.       target: 'add-location-button',
201.       action: matomo.ACTION_TYPES.OPEN,
202.     });
203.     setAddingLocationForCategoryId(categoryId);
204.   };
205. 
206.   /** Cancel adding location ΓÇö closes the combobox */
207.   const handleCancelAddLocation = () => {
208.     setAddingLocationForCategoryId(null);
209.   };
210. 
211.   /** Select location from combobox ΓÇö adds geography to local state only */
212.   const handleSelectLocation = (categoryId: string, location: LocationListItem) => {
213.     analyticsService.trackClick({
214.       source: 'confirm-portfolio-form',
215.       target: 'select-location',
216.       action: matomo.ACTION_TYPES.ACCESS,
217.     });
218. 
219.     // Update local state only - API call happens on "Apply & Continue"
220.     setLocalCategories((prev) =>
221.       (prev ?? []).map((cat) =>
222.         cat.id === categoryId
223.           ? { ...cat, geographies: [...cat.geographies, location.name] }
224.           : cat,
225.       ),
226.     );
227. 
228.     analyticsService.trackEvent({
229.       eventType: 'geography-add-local',
230.       eventParams: {
231.         source: 'confirm-portfolio-form',
232.         target: 'geography-add',
233.         action: matomo.ACTION_TYPES.SUCCESS,
234.       },
235.     });
236. 
237.     // Close combobox
238.     setAddingLocationForCategoryId(null);
239.   };
240. 
241.   return (
242.     <ConfirmPortfolio
243.       portfolioData={portfolioData}
244.       onApplyAndContinue={handleApplyAndContinue}
245.       onDeleteGeography={handleDeleteGeography}
246.       onGoBack={handleGoBack}
247.       onAddLocation={handleAddLocation}
248.       onAddCategory={handleAddCategory}
249.       onSelectCategory={handleSelectCategory}
250.       onRemoveCategory={handleRemoveCategory}
251.       onSelectLocation={handleSelectLocation}
252.       onCancelAddLocation={handleCancelAddLocation}
253.       addingLocationForCategoryId={addingLocationForCategoryId}
254.       pendingCategoryIds={pendingCategoryIds}
255.       isLoading={isSaving}
256.     />
257.   );
258. }
259. 
260. export default ConfirmPortfolioClient;"
}

