207.   const handleCancelAddLocation = () => {
208.     setAddingLocationForCategoryId(null);
209.   };
210. 
211.   /** Select location from combobox ΓÇö adds geography to local state only */
212.   const handleSelectLocation = (categoryId: string, location: LocationListItem) => {
213.     analyticsService.trackClick({
214.       source: 'confirm-portfolio-form',
215.       target: 'select-location',
216.       action: matomo.ACTION_TYPES.ACCESS,
217.     });
218. 
219.     // Update local state only - API call happens on "Apply & Continue"
220.     setLocalCategories((prev) =>
221.       (prev ?? []).map((cat) =>
222.         cat.id === categoryId
223.           ? { ...cat, geographies: [...cat.geographies, location.name] }
224.           : cat,
225.       ),
226.     );
