Result: {
  "resultType": "success",
  "textResultForLlm": "1. /**
2.  * Matomo Analytics Service
3.  * Provides standardized methods for tracking user actions and API events
4.  */
5. 
6. import { sendEvent } from '@socialgouv/matomo-next';
7. import { matomo } from './constants';
8. 
9. type EventParams = Record<string, string | number>;
10. 
11. /**
12.  * Current module name for tracking
13.  * Default: common/featurepage/dashboard
14.  * Can be updated using analyticsService.setModule()
15.  */
16. let currentModule = 'common/featurepage/dashboard';
17. 
18. /**
19.  * Get current pathname from window if in browser, otherwise use fallback
20.  */
21. function getCurrentPathname(): string {
22.   if (typeof window !== 'undefined') {
23.     return window.location.pathname;
24.   }
25.   return '/unknown';
26. }
27. 
28. /**
29.  * Build event name in the format: /module/{modulename}/path/{route}/event/{type}/key1/value1/key2/value2
30.  * @param pathname - Current route path (will be enclosed in {})
31.  * @param eventType - Type of event (click, scroll, etc.)
32.  * @param params - Additional key/value pairs
33.  */
34. function buildEventName(
35.   pathname: string,
36.   eventType: string,
37.   params: EventParams
38. ): string {
39.   const parts = [`/module/${currentModule}`, `path/{${pathname}}`, `event/${eventType}`];
40. 
41.   Object.entries(params).forEach(([key, value]) => {
42.     parts.push(`${key}/${value}`);
43.   });
44. 
45.   return `${parts.join('/')}`;
46. }
47. 
48. interface TrackClickParams {
49.   pathname?: string;
50.   source: string;
51.   target: string;
52.   action: string;
53.   value?: string;
54. }
55. 
56. interface TrackApiParams {
57.   pathname?: string;
58.   endpoint: string;
59.   method: string;
60.   status: 'success' | 'failure';
61.   statusCode?: number;
62. }
63. 
64. interface TrackScrollParams {
65.   pathname?: string;
66.   source: string;
67.   target: string;
68.   value?: string;
69. }
70. 
71. interface TrackViewParams {
72.   pathname?: string;
73.   source: string;
74.   target: string;
75. }
76. 
77. class MatomoAnalyticsService {
78.   /**
79.    * Set the current module name for tracking
80.    * This module will be used for all subsequent tracking events until updated
81.    * @param module - Module name (e.g., 'signin', 'dashboard', 'admin')
82.    */
83.   setModule(module: string): void {
84.     currentModule = module;
85.     console.log(`Matomo module set to: ${module}`);
86.   }
87. 
88.   /**
89.    * Get the current module name
90.    */
91.   getModule(): string {
92.     return currentModule;
93.   }
94. 
95.   /**
96.    * Track user click events
97.    * @param params.pathname - Optional pathname (auto-detected if not provided)
98.    */
99.   trackClick(params: TrackClickParams): void {
100.     const { pathname = getCurrentPathname(), source, target, action, value } = params;
101. 
102.     const eventParams: EventParams = {
103.       [matomo.ATTRIBUTES.SOURCE]: source,
104.       [matomo.ATTRIBUTES.TARGET]: target,
105.       [matomo.ATTRIBUTES.ACTION]: action,
106.     };
107. 
108.     if (value) {
109.       eventParams[matomo.ATTRIBUTES.VALUE] = value;
110.     }
111. 
112.     const eventName = buildEventName(pathname, matomo.EVENTS.CLICK, eventParams);
113. 
114.     sendEvent({
115.       category: matomo.TYPE.EVENT,
116.       action: matomo.EVENTS.CLICK,
117.       name: eventName,
118.     });
119. 
120.     console.log('Matomo trackClick:', eventName);
121.   }
122. 
123.   /**
124.    * Track API calls
125.    * @param params.pathname - Optional pathname (auto-detected if not provided)
126.    */
127.   trackApi(params: TrackApiParams): void {
128.     const { pathname = getCurrentPathname(), endpoint, method, status, statusCode } = params;
129. 
130.     const eventParams: EventParams = {
131.       endpoint: `{${endpoint}}`,
132.       method,
133.       status,
134.     };
135. 
136.     if (statusCode) {
137.       eventParams.statusCode = statusCode;
