1. /**
2.  * Matomo Analytics Service
3.  * Provides standardized methods for tracking user actions and API events
4.  */
5. 
6. import { sendEvent } from '@socialgouv/matomo-next';
7. import { matomo } from './constants';
8. 
9. type EventParams = Record<string, string | number>;
10. 
11. /**
12.  * Current module name for tracking
13.  * Default: common/featurepage/dashboard
14.  * Can be updated using analyticsService.setModule()
15.  */
16. let currentModule = 'common/featurepage/dashboard';
17. 
18. /**
19.  * Get current pathname from window if in browser, otherwise use fallback
20.  */
21. function getCurrentPathname(): string {
22.   if (typeof window !== 'undefined') {
23.     return window.location.pathname;
24.   }
25.   return '/unknown';
26. }
27. 
28. /**
29.  * Build event name in the format: /module/{modulename}/path/{route}/event/{type}/key1/value1/key2/value2
30.  * @param pathname - Current route path (will be enclosed in {})
31.  * @param eventType - Type of event (click, scroll, etc.)
32.  * @param params - Additional key/value pairs
33.  */
34. function buildEventName(
35.   pathname: string,
36.   eventType: string,
37.   params: EventParams
38. ): string {
39.   const parts = [`/module/${currentModule}`, `path/{${pathname}}`, `event/${eventType}`];
40. 
41.   Object.entries(params).forEach(([key, value]) => {
42.     parts.push(`${key}/${value}`);
43.   });
44. 
45.   return `${parts.join('/')}`;
46. }
47. 
48. interface TrackClickParams {
49.   pathname?: string;
50.   source: string;
51.   target: string;
52.   action: string;
53.   value?: string;
54. }
55. 
56. interface TrackApiParams {
57.   pathname?: string;
