67.   target: string;
68.   value?: string;
69. }
70. 
71. interface TrackViewParams {
72.   pathname?: string;
73.   source: string;
74.   target: string;
75. }
76. 
77. class MatomoAnalyticsService {
78.   /**
79.    * Set the current module name for tracking
80.    * This module will be used for all subsequent tracking events until updated
81.    * @param module - Module name (e.g., 'signin', 'dashboard', 'admin')
82.    */
83.   setModule(module: string): void {
84.     currentModule = module;
85.     console.log(`Matomo module set to: ${module}`);
86.   }
87. 
88.   /**
89.    * Get the current module name
90.    */
91.   getModule(): string {
92.     return currentModule;
93.   }
94. 
95.   /**
96.    * Track user click events
97.    * @param params.pathname - Optional pathname (auto-detected if not provided)
98.    */
99.   trackClick(params: TrackClickParams): void {
100.     const { pathname = getCurrentPathname(), source, target, action, value } = params;
101. 
102.     const eventParams: EventParams = {
103.       [matomo.ATTRIBUTES.SOURCE]: source,
104.       [matomo.ATTRIBUTES.TARGET]: target,
105.       [matomo.ATTRIBUTES.ACTION]: action,
106.     };
107. 
108.     if (value) {
109.       eventParams[matomo.ATTRIBUTES.VALUE] = value;
110.     }
111. 
112.     const eventName = buildEventName(pathname, matomo.EVENTS.CLICK, eventParams);
113. 
114.     sendEvent({
115.       category: matomo.TYPE.EVENT,
116.       action: matomo.EVENTS.CLICK,
117.       name: eventName,
118.     });
119. 
120.     console.log('Matomo trackClick:', eventName);
121.   }
122. 
123.   /**
124.    * Track API calls
125.    * @param params.pathname - Optional pathname (auto-detected if not provided)
126.    */
127.   trackApi(params: TrackApiParams): void {
