129. 
130.     const eventParams: EventParams = {
131.       endpoint: `{${endpoint}}`,
132.       method,
133.       status,
134.     };
135. 
136.     if (statusCode) {
137.       eventParams.statusCode = statusCode;
138.     }
139. 
140.     const eventName = buildEventName(pathname, 'api', eventParams);
141. 
142.     sendEvent({
143.       category: 'api',
144.       action: method,
145.       name: eventName,
146.     });
