  // ---- GET Available Locations (for combobox, paginated) ----
  {
    url: `${BASE_URL.DATAHUB}${API_ENDPOINTS.ONBOARDING_LOCATIONS}`,
    endpoint: 'getAvailableLocations',
    builder(builder: QueryBuilder) {
      return builder.query<LocationListResponse, LocationSearchParams>({
        query: (params) => {
          const searchParams = new URLSearchParams();
          if (params.page !== undefined) searchParams.set('page', String(params.page));
          if (params.limit !== undefined) searchParams.set('limit', String(params.limit));
          if (params.search) searchParams.set('search', params.search);
          if (params.excludeNames?.length) searchParams.set('excludeNames', params.excludeNames.join(','));
          const queryString = searchParams.toString();
          return `${API_ENDPOINTS.ONBOARDING_LOCATIONS}${queryString ? `?${queryString}` : ''}`;
        },
        providesTags: ['Onboarding'],
      });
    },
    mock() {
      return http.get('*/api/onboarding/locations', async ({ request }) => {
        await new Promise(resolve => setTimeout(resolve, 1000));

        const url = new URL(request.url);
        const page = parseInt(url.searchParams.get('page') || '1', 10);
        const limit = parseInt(url.searchParams.get('limit') || '10', 10);
        const search = url.searchParams.get('search') || '';
        const excludeNamesParam = url.searchParams.get('excludeNames') || '';
        const excludeNames = excludeNamesParam ? excludeNamesParam.split(',') : [];

        // Filter out excluded names
        let filtered = ALL_LOCATIONS.filter(location => !excludeNames.includes(location.name));

        // Filter by search term (case-insensitive partial match)
        if (search.trim()) {
          const searchLower = search.toLowerCase();
          filtered = filtered.filter(location => location.name.toLowerCase().includes(searchLower));
        }

        const total = filtered.length;
        const start = (page - 1) * limit;
        const paged = filtered.slice(start, start + limit);
        const hasMore = start + limit < total;

        return HttpResponse.json({
          success: true,
          data: paged,
          pagination: { page, limit, total, hasMore },
        } satisfies LocationListResponse);
      });
    },
  },

  // ---- GET Goals (global + category goals) ----
  {
    url: `${BASE_URL.DATAHUB}${API_ENDPOINTS.ONBOARDING_SET_GOALS}`,
    endpoint: 'getGoals',
    builder(builder: QueryBuilder) {
      return builder.query<GetGoalsResponse, void>({
        query: () => API_ENDPOINTS.ONBOARDING_SET_GOALS,
        providesTags: ['Onboarding'],
      });
    },
    mock() {
      return http.get('*/api/onboarding/set-goals', async () => {
        await new Promise(resolve => setTimeout(resolve, 800));
        const data = getGoalsFromStorage();
        return HttpResponse.json({
          success: true,
          data,
          message: 'Goals fetched successfully',
        } satisfies GetGoalsResponse);
      });
    },
  },

  // ---- POST Save Goals (+ mark goalsSet) ----
  {
    url: `${BASE_URL.DATAHUB}${API_ENDPOINTS.ONBOARDING_SET_GOALS}`,
    endpoint: 'saveGoals',
    builder(builder: QueryBuilder) {
      return builder.mutation<SetGoalsResponse, SetGoalsRequest>({
        query: (body) => ({
          url: API_ENDPOINTS.ONBOARDING_SET_GOALS,
          method: 'POST',
          body,
        }),
        invalidatesTags: ['Onboarding'],
      });
    },
    mock() {
      return http.post('*/api/onboarding/set-goals', async ({ request }) => {
        await new Promise(resolve => setTimeout(resolve, 1500));

        const body = (await request.json()) as SetGoalsRequest;

        // Persist goals to localStorage
        localStorage.setItem('onboardingGoals', JSON.stringify(body));

        // Mark goalsSet = true
        const status = getOnboardingStatusFromStorage();
        status.goalsSet = true;
        status.isOnboarded =
          status.portfolioConfirmed &&
          status.goalsSet &&
          status.insightsReviewed &&
          status.dataReviewed;
        updateOnboardingStatusInStorage(status);

        return HttpResponse.json({
          success: true,
          data: body,
          message: 'Goals saved successfully',
        } satisfies SetGoalsResponse);
      });
    },
  },
];

