"use client";
// @subframe/sync-disable

import React from "react";
import { FeatherArrowLeft } from "@subframe/core";
import { FeatherArrowRight } from "@subframe/core";
import { FeatherDollarSign } from "@subframe/core";
import { FeatherLeaf } from "@subframe/core";
import { FeatherShieldAlert } from "@subframe/core";
import { FeatherPlus } from "@subframe/core";
import { FeatherTrash2 } from "@subframe/core";
import { Button } from "@/ui/components/Button";
import { FancySlider } from "@/ui/components/FancySlider";
import { Select } from "@/ui/components/Select";
import type { SetGoalsProps, GoalTheme } from "@/types/onboarding";

function getIconForTheme(iconType: GoalTheme["iconType"]) {
  switch (iconType) {
    case "dollar":
      return <FeatherDollarSign className="text-body-2 font-body-2 text-subtext-color" />;
    case "shield":
      return <FeatherShieldAlert className="text-body-2 font-body-2 text-subtext-color" />;
    case "leaf":
      return <FeatherLeaf className="text-body-2 font-body-2 text-subtext-color" />;
  }
}

function getPriorityColorClass(priorityLabel: GoalTheme["priorityLabel"]) {
  switch (priorityLabel) {
    case "Low":
      return "text-neutral-500";
    case "Medium":
      return "text-warning-700";
    case "High":
      return "text-error-600";
  }
}

function SetGoals(props: SetGoalsProps) {
  const {
    globalGoals,
    categoryGoals,
    availablePortfolioCategories,
    onGlobalSliderChange,
    onCategorySliderChange,
    onAddCategoryGoal,
    onDeleteCategoryGoal,
    onGoBack,
    onApplyAndContinue,
    isLoading,
  } = props;

  return (
    <div className="flex grow shrink-0 basis-0 flex-col items-start gap-6 self-stretch px-10 py-8 mobile:px-0 mobile:pt-0 mobile:pb-8">
      {/* Navigation header */}
      <div className="flex w-full items-center gap-2">
        <div className="flex grow shrink-0 basis-0 items-start gap-2">
          <button
            className="flex items-center gap-3 cursor-pointer bg-transparent border-none"
            onClick={onGoBack}
            data-testid="btn-goals-go-back"
          >
            <FeatherArrowLeft className="text-body-2 font-body-2 text-default-font" />
            <span className="text-body-2 font-body-2 text-default-font">Go back</span>
          </button>
        </div>
        <Button
          variant="gradient"
          iconRight={<FeatherArrowRight />}
          loading={isLoading}
          onClick={onApplyAndContinue}
          data-testid="btn-goals-apply-continue"
        >
          Apply &amp; Continue
        </Button>
      </div>

      {/* Section heading */}
      <span
        className="h-3 text-overline font-overline text-default-font uppercase tracking-[.5em]"
        data-testid="lbl-goals-heading"
      >
        Set Your Goals
      </span>

      {/* Global goals */}
      <div className="flex w-full flex-col items-start gap-3">
        <span className="text-body-bold font-body-bold text-default-font">
          Global Goals
        </span>
        <div className="flex w-full flex-col items-start gap-3">
          {globalGoals.map((theme) => (
            <div
              key={theme.id}
              className="flex w-full max-w-[480px] flex-col items-start rounded-rounded-sm border border-solid border-neutral-border bg-neutral-50"
            >
              <div className="flex w-full items-center gap-6 pl-3 pr-4 pt-3 pb-2">
                <div className="flex grow shrink-0 basis-0 items-center gap-2">
                  {getIconForTheme(theme.iconType)}
                  <span className="grow shrink-0 basis-0 text-body-2 font-body-2 text-default-font">
                    {theme.label}
                  </span>
                </div>
                <span
                  className={`text-sub-title-1 font-sub-title-1 text-right ${getPriorityColorClass(theme.priorityLabel)}`}
                  data-testid={`lbl-global-${theme.id}-priority`}
                >
                  {theme.priorityLabel}
                </span>
              </div>
              <div className="flex w-full flex-col items-start gap-2 rounded-xl bg-default-background px-4 pt-2 pb-2.5 shadow-md">
                <FancySlider
                  markers={true}
                  value={[theme.sliderValue]}
                  onValueChange={(val) => onGlobalSliderChange(theme.id, val[0])}
                  min={0}
                  max={100}
                  step={1}
                  data-testid={`slider-global-${theme.id}`}
                />
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Category goals */}
      <div className="flex w-full flex-col items-start gap-3">
        <span className="text-body-bold font-body-bold text-default-font">
          Category Goals
        </span>
        <div className="flex w-full flex-wrap items-start gap-4">
          {categoryGoals.map((catGoal) => (
            <div
              key={catGoal.categoryId}
              className="flex w-full min-w-[320px] max-w-[384px] flex-col items-start justify-center rounded-rounded-lg bg-white shadow-elevation---01"
              data-testid={`card-category-goal-${catGoal.categoryId}`}
            >
              <div className="flex w-full flex-col items-start gap-4 px-6 py-6">
                <div className="flex w-full items-center gap-4">
                  <span className="grow shrink-0 basis-0 text-heading-6 font-heading-6 text-default-font">
                    {catGoal.categoryName}
                  </span>
                  <button
                    type="button"
                    className="flex items-center justify-center p-0 bg-transparent border-none cursor-pointer"
                    onClick={() => onDeleteCategoryGoal(catGoal.categoryId)}
                    data-testid={`btn-delete-category-goal-${catGoal.categoryId}`}
                    aria-label={`Remove ${catGoal.categoryName} goals`}
                  >
                    <FeatherTrash2 className="text-heading-5 font-heading-5 text-neutral-400 hover:text-error-500" />
                  </button>
                </div>
                <div className="flex w-full flex-col items-start gap-4">
                  {catGoal.themes.map((theme) => (
                    <div
                      key={theme.id}
                      className="flex w-full flex-col items-start rounded-rounded-sm border border-solid border-neutral-border bg-neutral-50"
                    >
                      <div className="flex w-full items-center gap-6 pl-3 pr-4 pt-3 pb-2">
                        <div className="flex grow shrink-0 basis-0 items-center gap-2">
                          {getIconForTheme(theme.iconType)}
                          <span className="grow shrink-0 basis-0 text-body-2 font-body-2 text-default-font">
                            {theme.label}
                          </span>
                        </div>
                        <span
                          className={`text-sub-title-1 font-sub-title-1 text-right ${getPriorityColorClass(theme.priorityLabel)}`}
                          data-testid={`lbl-category-${catGoal.categoryId}-${theme.id}-priority`}
                        >
                          {theme.priorityLabel}
                        </span>
                      </div>
                      <div className="flex w-full flex-col items-start gap-2 rounded-xl bg-default-background px-4 pt-2 pb-2.5 shadow-md">
                        <FancySlider
                          markers={true}
                          value={[theme.sliderValue]}
                          onValueChange={(val) =>
                            onCategorySliderChange(catGoal.categoryId, theme.id, val[0])
                          }
                          min={0}
                          max={100}
                          step={1}
                          data-testid={`slider-category-${catGoal.categoryId}-${theme.id}`}
                        />
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          ))}

          {/* Add category goal selector */}
          {availablePortfolioCategories.length > 0 && (
            <div className="flex w-full min-w-[256px] max-w-[288px] flex-col items-start justify-center gap-3">
              <Select
                label="Add Category Goal"
                placeholder="Select a category"
                value=""
                onValueChange={(categoryId) => {
                  const cat = availablePortfolioCategories.find((c) => c.id === categoryId);
                  if (cat) onAddCategoryGoal(cat.id, cat.title);
                }}
                data-testid="select-goals-add-category"
              >
                {availablePortfolioCategories.map((cat) => (
                  <Select.Item key={cat.id} value={cat.id} data-testid={`option-goals-category-${cat.id}`}>
                    {cat.title}
                  </Select.Item>
                ))}
              </Select>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default SetGoals;

