'use client';

import { useEffect, useMemo, useState } from 'react';
import { analyticsService, matomo } from '@/libs/matomo';
import {
  useGetGoalsQuery,
  useSaveGoalsMutation,
  useGetOnboardingStatusQuery,
  useGetPortfolioDataQuery,
} from '@/libs/store/api/onboardingApi';
import { useOnboardingWorkflowPage } from '@/hooks/useOnboardingWorkflowPage';
import SetGoals from '@/subframe-pages/Onboarding/SetGoals';
import { PortalLoader } from '@/components/PortalLoader';
import type { GoalTheme, CategoryGoal, PortfolioCategory } from '@/types/onboarding';
import { DEFAULT_GLOBAL_GOALS } from '@/libs/http/mocks/data/OnboardingMockData';

function getPriorityLabel(value: number): GoalTheme['priorityLabel'] {
  if (value <= 33) return 'Low';
  if (value <= 66) return 'Medium';
  return 'High';
}

function SetGoalsClient() {
  // 1. Onboarding workflow hook ΓÇö manages sidebar stepper + step validation
  //    expectedStepIndex: 0=Confirm Portfolio, 1=Set Goals, 2=Key Insights, 3=Review Data
  const { isReady, router } = useOnboardingWorkflowPage({
    expectedStepIndex: 1,
    sidebarDescription:
      "Next, set your procurement goals. Prioritize cost savings, risk management, and ESG across your portfolio.",
  });

  // 2. Analytics module (FIRST useEffect)
  useEffect(() => {
    analyticsService.setModule('onboarding-set-goals');
  }, []);

  // 3. RTK Query hooks ΓÇö all before conditional returns
  const { data: goalsData, isLoading: isLoadingGoals } = useGetGoalsQuery();
  const { data: portfolioData, isLoading: isLoadingPortfolio } = useGetPortfolioDataQuery();
  const [saveGoals, { isLoading: isSaving }] = useSaveGoalsMutation();
  const { refetch: refetchOnboardingStatus } = useGetOnboardingStatusQuery();

  // 4. Local state
  const [localGlobalGoals, setLocalGlobalGoals] = useState<GoalTheme[] | null>(null);
  const [localCategoryGoals, setLocalCategoryGoals] = useState<CategoryGoal[] | null>(null);

  // 5. Sync API data to local state on first load
  useEffect(() => {
    if (goalsData?.data?.globalGoals && localGlobalGoals === null) {
      setLocalGlobalGoals([...goalsData.data.globalGoals]);
    }
  }, [goalsData, localGlobalGoals]);

  useEffect(() => {
    if (goalsData?.data?.categoryGoals && localCategoryGoals === null) {
      setLocalCategoryGoals([...goalsData.data.categoryGoals]);
    }
  }, [goalsData, localCategoryGoals]);

  // 6. Derived state
  const globalGoals = useMemo<GoalTheme[]>(() => {
    return localGlobalGoals ?? goalsData?.data?.globalGoals ?? [...DEFAULT_GLOBAL_GOALS];
  }, [localGlobalGoals, goalsData]);

  const categoryGoals = useMemo<CategoryGoal[]>(() => {
    return localCategoryGoals ?? goalsData?.data?.categoryGoals ?? [];
  }, [localCategoryGoals, goalsData]);

  const portfolioCategories = useMemo<PortfolioCategory[]>(() => {
    return portfolioData?.data?.categories ?? [];
  }, [portfolioData]);

  const availablePortfolioCategories = useMemo<PortfolioCategory[]>(() => {
    const addedIds = new Set(categoryGoals.map((cg) => cg.categoryId));
    return portfolioCategories.filter((cat) => !addedIds.has(cat.id));
  }, [portfolioCategories, categoryGoals]);

  // 7. Loading gate ΓÇö AFTER all hooks
  if (isLoadingGoals || isLoadingPortfolio || !isReady) {
    return <PortalLoader />;
  }

  // 8. Event handlers

  const handleGlobalSliderChange = (themeId: string, value: number) => {
    analyticsService.trackClick({
      source: 'set-goals-page',
      target: `slider-global-${themeId}`,
      action: matomo.ACTION_TYPES.UPDATE,
    });
    setLocalGlobalGoals((prev) =>
      (prev ?? [...DEFAULT_GLOBAL_GOALS]).map((theme) =>
        theme.id === themeId
          ? { ...theme, sliderValue: value, priorityLabel: getPriorityLabel(value) }
          : theme,
      ),
    );
  };

  const handleCategorySliderChange = (categoryId: string, themeId: string, value: number) => {
    analyticsService.trackClick({
      source: 'set-goals-page',
      target: `slider-category-${categoryId}-${themeId}`,
      action: matomo.ACTION_TYPES.UPDATE,
    });
    setLocalCategoryGoals((prev) =>
      (prev ?? []).map((catGoal) =>
        catGoal.categoryId === categoryId
          ? {
              ...catGoal,
              themes: catGoal.themes.map((theme) =>
                theme.id === themeId
                  ? { ...theme, sliderValue: value, priorityLabel: getPriorityLabel(value) }
                  : theme,
              ),
            }
          : catGoal,
      ),
    );
  };

  const handleAddCategoryGoal = (categoryId: string, categoryName: string) => {
    analyticsService.trackClick({
      source: 'set-goals-page',
      target: 'add-category-goal',
      action: matomo.ACTION_TYPES.OPEN,
    });

    const newCategoryGoal: CategoryGoal = {
      categoryId,
      categoryName,
      themes: DEFAULT_GLOBAL_GOALS.map((theme) => ({ ...theme })),
    };
    setLocalCategoryGoals((prev) => [...(prev ?? []), newCategoryGoal]);
  };

  const handleDeleteCategoryGoal = (categoryId: string) => {
    analyticsService.trackClick({
      source: 'set-goals-page',
      target: 'delete-category-goal',
      action: matomo.ACTION_TYPES.CLOSE,
    });
    setLocalCategoryGoals((prev) =>
      (prev ?? []).filter((cg) => cg.categoryId !== categoryId),
    );
  };

  const handleGoBack = () => {
    analyticsService.trackClick({
      source: 'set-goals-page',
      target: 'go-back-button',
      action: matomo.ACTION_TYPES.VIEW,
    });
    router.push('/onboarding/confirm-portfolio');
  };

  const handleApplyAndContinue = async () => {
    analyticsService.trackClick({
      source: 'set-goals-page',
      target: 'apply-continue-button',
      action: matomo.ACTION_TYPES.ACCESS,
    });

    try {
      await saveGoals({ globalGoals, categoryGoals }).unwrap();

      analyticsService.trackEvent({
        eventType: 'goals-save-success',
        eventParams: {
          source: 'set-goals-page',
          target: 'goals-save',
          action: matomo.ACTION_TYPES.SUCCESS,
        },
      });

      await refetchOnboardingStatus();

      router.push('/onboarding/key-insights');
    } catch (err) {
      analyticsService.trackEvent({
        eventType: 'goals-save-failure',
        eventParams: {
          source: 'set-goals-page',
          target: 'goals-save',
          action: matomo.ACTION_TYPES.FAILURE,
        },
      });
      console.error('Failed to save goals:', err);
    }
  };

  // 9. Render
  return (
    <SetGoals
      globalGoals={globalGoals}
      categoryGoals={categoryGoals}
      availablePortfolioCategories={availablePortfolioCategories}
      onGlobalSliderChange={handleGlobalSliderChange}
      onCategorySliderChange={handleCategorySliderChange}
      onAddCategoryGoal={handleAddCategoryGoal}
      onDeleteCategoryGoal={handleDeleteCategoryGoal}
      onGoBack={handleGoBack}
      onApplyAndContinue={handleApplyAndContinue}
      isLoading={isSaving}
    />
  );
}

export default SetGoalsClient;

