23. function SetGoalsClient() {
24.   // 1. Onboarding workflow hook ΓÇö manages sidebar stepper + step validation
25.   //    expectedStepIndex: 0=Confirm Portfolio, 1=Set Goals, 2=Key Insights, 3=Review Data
