30.   });
31. 
32.   // 2. Analytics module (FIRST useEffect)
33.   useEffect(() => {
34.     analyticsService.setModule('onboarding-set-goals');
35.   }, []);
36. 
37.   // 3. RTK Query hooks ΓÇö all before conditional returns
38.   const { data: goalsData, isLoading: isLoadingGoals } = useGetGoalsQuery();
39.   const { data: portfolioData, isLoading: isLoadingPortfolio } = useGetPortfolioDataQuery();
40.   const [saveGoals, { isLoading: isSaving }] = useSaveGoalsMutation();
41.   const { refetch: refetchOnboardingStatus } = useGetOnboardingStatusQuery();
42. 
43.   // 4. Local state
44.   const [localGlobalGoals, setLocalGlobalGoals] = useState<GoalTheme[] | null>(null);
45.   const [localCategoryGoals, setLocalCategoryGoals] = useState<CategoryGoal[] | null>(null);
46. 
47.   // 5. Sync API data to local state on first load
48.   useEffect(() => {
