56.       setLocalCategoryGoals([...goalsData.data.categoryGoals]);
57.     }
58.   }, [goalsData, localCategoryGoals]);
59. 
60.   // 6. Derived state
61.   const globalGoals = useMemo<GoalTheme[]>(() => {
62.     return localGlobalGoals ?? goalsData?.data?.globalGoals ?? [...DEFAULT_GLOBAL_GOALS];
