102.       source: 'set-goals-page',
103.       target: `slider-category-${categoryId}-${themeId}`,
104.       action: matomo.ACTION_TYPES.UPDATE,
105.     });
106.     setLocalCategoryGoals((prev) =>
107.       (prev ?? []).map((catGoal) =>
108.         catGoal.categoryId === categoryId
109.           ? {
110.               ...catGoal,
111.               themes: catGoal.themes.map((theme) =>
112.                 theme.id === themeId
113.                   ? { ...theme, sliderValue: value, priorityLabel: getPriorityLabel(value) }
114.                   : theme,
