2. 
3. import { useEffect, useMemo, useState } from 'react';
4. import { analyticsService, matomo } from '@/libs/matomo';
5. import {
6.   useGetGoalsQuery,
7.   useSaveGoalsMutation,
8.   useGetOnboardingStatusQuery,
9.   useGetPortfolioDataQuery,
10. } from '@/libs/store/api/onboardingApi';
11. import { useOnboardingWorkflowPage } from '@/hooks/useOnboardingWorkflowPage';
12. import SetGoals from '@/subframe-pages/Onboarding/SetGoals';
13. import { PortalLoader } from '@/components/PortalLoader';
14. import type { GoalTheme, CategoryGoal, PortfolioCategory } from '@/types/onboarding';
15. import { DEFAULT_GLOBAL_GOALS } from '@/types/onboarding';
16. 
17. function getPriorityLabel(value: number): GoalTheme['priorityLabel'] {
18.   if (value <= 33) return 'Low';
19.   if (value <= 66) return 'Medium';
20.   return 'High';
21. }
22. 
23. function SetGoalsClient() {
24.   // 1. Onboarding workflow hook ΓÇö manages sidebar stepper + step validation
25.   //    expectedStepIndex: 0=Confirm Portfolio, 1=Set Goals, 2=Key Insights, 3=Review Data
26.   const { isReady, router } = useOnboardingWorkflowPage({
27.     expectedStepIndex: 1,
28.     sidebarDescription:
29.       "Next, set your procurement goals. Prioritize cost savings, risk management, and ESG across your portfolio.",
30.   });
31. 
32.   // 2. Analytics module (FIRST useEffect)
33.   useEffect(() => {
34.     analyticsService.setModule('onboarding-set-goals');
35.   }, []);
36. 
37.   // 3. RTK Query hooks ΓÇö all before conditional returns
38.   const { data: goalsData, isLoading: isLoadingGoals } = useGetGoalsQuery();
39.   const { data: portfolioData, isLoading: isLoadingPortfolio } = useGetPortfolioDataQuery();
40.   const [saveGoals, { isLoading: isSaving }] = useSaveGoalsMutation();
41.   const { refetch: refetchOnboardingStatus } = useGetOnboardingStatusQuery();
42. 
43.   // 4. Local state
44.   const [localGlobalGoals, setLocalGlobalGoals] = useState<GoalTheme[] | null>(null);
45.   const [localCategoryGoals, setLocalCategoryGoals] = useState<CategoryGoal[] | null>(null);
46. 
47.   // 5. Sync API data to local state on first load
48.   useEffect(() => {
49.     if (goalsData?.data?.globalGoals && localGlobalGoals === null) {
50.       setLocalGlobalGoals([...goalsData.data.globalGoals]);
51.     }
52.   }, [goalsData, localGlobalGoals]);
53. 
54.   useEffect(() => {
55.     if (goalsData?.data?.categoryGoals && localCategoryGoals === null) {
56.       setLocalCategoryGoals([...goalsData.data.categoryGoals]);
57.     }
58.   }, [goalsData, localCategoryGoals]);
59. 
60.   // 6. Derived state
61.   const globalGoals = useMemo<GoalTheme[]>(() => {
62.     return localGlobalGoals ?? goalsData?.data?.globalGoals ?? [...DEFAULT_GLOBAL_GOALS];
63.   }, [localGlobalGoals, goalsData]);
64. 
65.   const categoryGoals = useMemo<CategoryGoal[]>(() => {
66.     return localCategoryGoals ?? goalsData?.data?.categoryGoals ?? [];
67.   }, [localCategoryGoals, goalsData]);
68. 
69.   const portfolioCategories = useMemo<PortfolioCategory[]>(() => {
70.     return portfolioData?.data?.categories ?? [];
71.   }, [portfolioData]);
72. 
73.   const availablePortfolioCategories = useMemo<PortfolioCategory[]>(() => {
74.     const addedIds = new Set(categoryGoals.map((cg) => cg.categoryId));
75.     return portfolioCategories.filter((cat) => !addedIds.has(cat.id));
76.   }, [portfolioCategories, categoryGoals]);
77. 
78.   // 7. Loading gate ΓÇö AFTER all hooks
79.   if (isLoadingGoals || isLoadingPortfolio || !isReady) {
80.     return <PortalLoader />;
81.   }
82. 
83.   // 8. Event handlers
84. 
85.   const handleGlobalSliderChange = (themeId: string, value: number) => {
86.     analyticsService.trackClick({
87.       source: 'set-goals-page',
88.       target: `slider-global-${themeId}`,
89.       action: matomo.ACTION_TYPES.UPDATE,
90.     });
91.     setLocalGlobalGoals((prev) =>
92.       (prev ?? [...DEFAULT_GLOBAL_GOALS]).map((theme) =>
93.         theme.id === themeId
94.           ? { ...theme, sliderValue: value, priorityLabel: getPriorityLabel(value) }
95.           : theme,
96.       ),
97.     );
98.   };
99. 
100.   const handleCategorySliderChange = (categoryId: string, themeId: string, value: number) => {
101.     analyticsService.trackClick({
102.       source: 'set-goals-page',
103.       target: `slider-category-${categoryId}-${themeId}`,
104.       action: matomo.ACTION_TYPES.UPDATE,
105.     });
106.     setLocalCategoryGoals((prev) =>
107.       (prev ?? []).map((catGoal) =>
108.         catGoal.categoryId === categoryId
109.           ? {
110.               ...catGoal,
111.               themes: catGoal.themes.map((theme) =>
112.                 theme.id === themeId
113.                   ? { ...theme, sliderValue: value, priorityLabel: getPriorityLabel(value) }
114.                   : theme,
115.               ),
116.             }
117.           : catGoal,
118.       ),
119.     );
120.   };
121. 
122.   const handleAddCategoryGoal = (categoryId: string, categoryName: string) => {
123.     analyticsService.trackClick({
124.       source: 'set-goals-page',
125.       target: 'add-category-goal',
126.       action: matomo.ACTION_TYPES.ACCESS,
127.     });
128. 
129.     const newCategoryGoal: CategoryGoal = {
130.       categoryId,
131.       categoryName,
132.       themes: DEFAULT_GLOBAL_GOALS.map((theme) => ({ ...theme })),
133.     };
134.     setLocalCategoryGoals((prev) => [...(prev ?? []), newCategoryGoal]);
135.   };
136. 
137.   const handleDeleteCategoryGoal = (categoryId: string) => {
138.     analyticsService.trackClick({
139.       source: 'set-goals-page',
140.       target: 'delete-category-goal',
141.       action: matomo.ACTION_TYPES.CLEAR,
142.     });
143.     setLocalCategoryGoals((prev) =>
144.       (prev ?? []).filter((cg) => cg.categoryId !== categoryId),
145.     );
146.   };
147. 
148.   const handleGoBack = () => {
149.     analyticsService.trackClick({
150.       source: 'set-goals-page',
151.       target: 'go-back-button',
152.       action: matomo.ACTION_TYPES.VIEW,
153.     });
154.     router.push('/onboarding/confirm-portfolio');
155.   };
156. 
157.   const handleApplyAndContinue = async () => {
158.     analyticsService.trackClick({
159.       source: 'set-goals-page',
160.       target: 'apply-continue-button',
161.       action: matomo.ACTION_TYPES.ACCESS,
162.     });
163. 
164.     try {
165.       await saveGoals({ globalGoals, categoryGoals }).unwrap();
166. 
167.       analyticsService.trackEvent({
168.         eventType: 'goals-save-success',
169.         eventParams: {
170.           source: 'set-goals-page',
171.           target: 'goals-save',
172.           action: matomo.ACTION_TYPES.SUCCESS,
173.         },
174.       });
175. 
176.       await refetchOnboardingStatus();
177. 
178.       router.push('/onboarding/key-insights');
179.     } catch (err) {
180.       analyticsService.trackEvent({
181.         eventType: 'goals-save-failure',
182.         eventParams: {
183.           source: 'set-goals-page',
184.           target: 'goals-save',
185.           action: matomo.ACTION_TYPES.FAILURE,
186.         },
187.       });
188.       console.error('Failed to save goals:', err);
189.     }
190.   };
191. 
192.   // 9. Render
193.   return (
194.     <SetGoals
195.       globalGoals={globalGoals}
196.       categoryGoals={categoryGoals}
197.       availablePortfolioCategories={availablePortfolioCategories}
198.       onGlobalSliderChange={handleGlobalSliderChange}
199.       onCategorySliderChange={handleCategorySliderChange}
200.       onAddCategoryGoal={handleAddCategoryGoal}
201.       onDeleteCategoryGoal={handleDeleteCategoryGoal}
202.       onGoBack={handleGoBack}
203.       onApplyAndContinue={handleApplyAndContinue}
204.       isLoading={isSaving}
205.     />
206.   );
207. }
208. 
209. export default SetGoalsClient;
210. "
}

